package dev.aperture.editor.imgui;
import imgui.ImGui;import imgui.flag.ImGuiWindowFlags;
final class EditorStatusBar{private final ApertureUiContext c;EditorStatusBar(ApertureUiContext c){this.c=c;}void render(){var v=ImGui.getMainViewport();ImGui.setNextWindowPos(v.getWorkPosX(),v.getWorkPosY()+v.getWorkSizeY()-ApertureStyle.STATUS_BAR_HEIGHT);ImGui.setNextWindowSize(v.getWorkSizeX(),ApertureStyle.STATUS_BAR_HEIGHT);int flags=ImGuiWindowFlags.NoTitleBar|ImGuiWindowFlags.NoResize|ImGuiWindowFlags.NoMove|ImGuiWindowFlags.NoDocking|ImGuiWindowFlags.NoScrollbar;ImGui.begin("Aperture Status##Status",flags);float[] color=c.mode==ApertureUiContext.Mode.RUNTIME?ApertureStyle.RUNTIME:ApertureStyle.BLUE;ImGui.textColored(color[0],color[1],color[2],1,c.mode+" MODE");ImGui.sameLine();ImGui.text(c.session.selection().snapshot().objectIds().size()+" selected | Snap: "+(c.snap?"On":"Off"));ImGui.end();}}
